    Assert.Contains("bold", result.Content.ToString().ToLower());
    Assert.Contains("text.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsPreprocessingAggressive()
        {
            // Aggressive preset removes nav, footer, aside unconditionally
            var result = HtmlToMarkdownRs.Convert("<nav>Menu</nav><article><h1>Title</h1><p>Content</p></article><aside>Sidebar</aside><footer>Footer</footer>", new ConversionOptions { Preprocessing = JsonSerializer.Deserialize<PreprocessingOptions>("{\"preset\":\"Aggressive\"}", ConfigOptions)! });
    Assert.Contains("title", result.Content.ToString().ToLower());
    Assert.Contains("content", result.Content.ToString().ToLower());
    Assert.DoesNotContain("Menu", result.Content.ToString());

        }

        [Fact]
        public void Test_OptionsPreprocessingEnabledFalseSkipsCleanup()
        {
            // Disabling preprocessing entirely preserves elements the standard preset would remove
            var result = HtmlToMarkdownRs.Convert("<nav>NavSection</nav><p>Paragraph</p>", new ConversionOptions { Preprocessing = JsonSerializer.Deserialize<PreprocessingOptions>("{\"enabled\":false}", ConfigOptions)! });
    Assert.Contains("navsection", result.Content.ToString().ToLower());
    Assert.Contains("paragraph", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsPreprocessingMinimal()
        {
            // Minimal preset preserves nav, footer, aside
            var result = HtmlToMarkdownRs.Convert("<nav>Navigation</nav><p>Content</p><footer>Footer</footer>", new ConversionOptions { Preprocessing = JsonSerializer.Deserialize<PreprocessingOptions>("{\"preset\":\"Minimal\"}", ConfigOptions)! });
    Assert.Contains("navigation", result.Content.ToString().ToLower());
    Assert.Contains("content", result.Content.ToString().ToLower());
    Assert.Contains("footer", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsPreprocessingRemoveForms()
        {
            // Forms are removed when remove_forms is true
            var result = HtmlToMarkdownRs.Convert("<p>Before</p><form><input type='text'/><button>Submit</button></form><p>After</p>", new ConversionOptions { Preprocessing = JsonSerializer.Deserialize<PreprocessingOptions>("{\"remove_forms\":true}", ConfigOptions)! });
    Assert.Contains("before", result.Content.ToString().ToLower());
    Assert.Contains("after", result.Content.ToString().ToLower());
    Assert.DoesNotContain("Submit", result.Content.ToString());

        }

        [Fact]
        public void Test_OptionsPreprocessingRemoveNavigationFalseKeepsNav()
        {
            // Setting remove_navigation to false preserves nav and aside elements
            var result = HtmlToMarkdownRs.Convert("<nav>SiteMenu</nav><main><p>MainContent</p></main><aside>SidebarText</aside>", new ConversionOptions { Preprocessing = JsonSerializer.Deserialize<PreprocessingOptions>("{\"remove_navigation\":false}", ConfigOptions)! });
    Assert.Contains("sitemenu", result.Content.ToString().ToLower());
    Assert.Contains("maincontent", result.Content.ToString().ToLower());
    Assert.Contains("sidebartext", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsPreserveTagsIframe()
        {
            // Iframe tags preserved as raw HTML in output
            var result = HtmlToMarkdownRs.Convert("<p>Before</p><iframe src='video.html' width='560'></iframe><p>After</p>", new ConversionOptions { PreserveTags = new List<string> { "iframe" } });
    Assert.Contains("before", result.Content.ToString().ToLower());
    Assert.Contains("after", result.Content.ToString().ToLower());
    Assert.Contains("<iframe", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsSkipImagesTrue()
        {
            // Images are omitted from output when skipImages is true
            var result = HtmlToMarkdownRs.Convert("<p>Before <img src='test.jpg' alt='photo'> After</p>", new ConversionOptions { SkipImages = true });
    Assert.Contains("before", result.Content.ToString().ToLower());
    Assert.Contains("after", result.Content.ToString().ToLower());
    Assert.DoesNotContain("photo", result.Content.ToString());

        }

        [Fact]
        public void Test_OptionsStripNewlines()
        {
            // Strip newlines produces single-line paragraphs
            var result = HtmlToMarkdownRs.Convert("<p>First paragraph.</p><p>Second paragraph.</p>", new ConversionOptions { StripNewlines = true });
    Assert.Contains("first paragraph.", result.Content.ToString().ToLower());
    Assert.Contains("second paragraph.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsStripTagsDivSpan()
        {
            // Div and span tags stripped but content preserved
            var result = HtmlToMarkdownRs.Convert("<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", new ConversionOptions { StripTags = new List<string> { "div", "span" } });
    Assert.Contains("inside div", result.Content.ToString().ToLower());
    Assert.Contains("span text", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsStrongEmUnderscore()
        {
            // Strong and em tags use underscore symbol instead of asterisk
            var result = HtmlToMarkdownRs.Convert("<p><strong>bold</strong> and <em>italic</em></p>", new ConversionOptions { StrongEmSymbol = "_" });
    Assert.Contains("__bold__", result.Content.ToString().ToLower());
    Assert.Contains("_italic_", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsSubSymbolTilde()
        {
            // Subscript rendered with tilde symbol
            var result = HtmlToMarkdownRs.Convert("<p>H<sub>2</sub>O</p>", new ConversionOptions { SubSymbol = "~" });
    Assert.Contains("~2~", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsSupSymbolCaret()
        {
            // Superscript rendered with caret symbol
            var result = HtmlToMarkdownRs.Convert("<p>x<sup>2</sup></p>", new ConversionOptions { SupSymbol = "^" });
    Assert.Contains("^2^", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsUrlEscapeStyleAngleDefault()
        {
            // Default angle style wraps URLs containing spaces in angle brackets
            var result = HtmlToMarkdownRs.Convert("<a href=\"/file (1).pdf\">file</a>", new ConversionOptions { UrlEscapeStyle = "angle" });
    Assert.Contains("</file (1).pdf>", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsUrlEscapeStylePercentAngleBracketsInUrl()
        {
            // Percent style encodes angle brackets in link URLs from issue 392
            var result = HtmlToMarkdownRs.Convert("<a href=\"/file (1) <draft>.pdf\">file</a>", new ConversionOptions { UrlEscapeStyle = "percent" });
    Assert.Contains("/file%20%281%29%20%3cdraft%3e.pdf", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsUrlEscapeStylePercentImage()
        {
            // Percent style encodes special characters in image src URLs
            var result = HtmlToMarkdownRs.Convert("<img src=\"/img (1) <draft>.png\" alt=\"alt\">", new ConversionOptions { UrlEscapeStyle = "percent" });
    Assert.Contains("/img%20%281%29%20%3cdraft%3e.png", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsUrlEscapeStylePercentLink()
        {
            // Percent style encodes spaces and parens in link URLs
            var result = HtmlToMarkdownRs.Convert("<a href=\"/file (1).pdf\">file</a>", new ConversionOptions { UrlEscapeStyle = "percent" });
    Assert.Contains("/file%20%281%29.pdf", result.Content.ToString().ToLower());
    Assert.DoesNotContain("</", result.Content.ToString());

        }

        [Fact]
        public void Test_OptionsWhitespaceNormalized()
        {
            // Normalized whitespace mode collapses multiple spaces
            var result = HtmlToMarkdownRs.Convert("<p>Text   with    extra   spaces.</p>", new ConversionOptions { WhitespaceMode = WhitespaceMode.Normalized });
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("text", result.Content.ToString().ToLower());
    Assert.Contains("with", result.Content.ToString().ToLower());
    Assert.Contains("extra", result.Content.ToString().ToLower());
    Assert.Contains("spaces.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsWhitespaceStrict()
        {
            // Strict whitespace mode preserves whitespace as-is
            var result = HtmlToMarkdownRs.Convert("<p>Preserved   spacing.</p>", new ConversionOptions { WhitespaceMode = WhitespaceMode.Strict });
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("preserved", result.Content.ToString().ToLower());
    Assert.Contains("spacing.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsWrapDisabled()
        {
            // Wrap option disabled preserves long lines without breaking
            var result = HtmlToMarkdownRs.Convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", new ConversionOptions { Wrap = false });
    Assert.Contains("this is a long paragraph that should not be wrapped at all because wrapping is disabled.", result.Content.ToString().ToLower());

        }

        [Fact]
        public void Test_OptionsWrapEnabled()
        {
            // Wrap option enabled with custom width wraps long lines
            var result = HtmlToMarkdownRs.Convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", new ConversionOptions { Wrap = true, WrapWidth = 40 });
    Assert.False(string.IsNullOrEmpty(result.Content?.ToString()));
    Assert.Contains("this is a long paragraph", result.Content.ToString().ToLower());

        }


    }
}
